		Name: "rate_limiter_requests_total",
		Help: "Total number of requests",
	}, []string{"client_id"})
	metricLimitExceeded = promauto.NewCounterVec(prometheus.CounterOpts{
		Name: "rate_limiter_limit_exceeded_total",
		Help: "Total number of limit exceeded",
	}, []string{"client_id"})
)

type RateLimiter struct {
	limits map[string]int64 // client ID -> limit
}

func NewRateLimiter(limits map[string]int64) *RateLimiter {
	return &RateLimiter{limits: limits}
}

func (r *RateLimiter) Allow(clientID string, now time.Time) bool {
	limit, ok := r.limits[clientID]
	if!ok {
		log.Printf("Client %s not found in limits", clientID)
		return false
